"use client"

import { useState } from "react"
import { motion, AnimatePresence } from "framer-motion"
import { ShoppingCart, Trash2, Plus, Minus, Package, CreditCard } from "lucide-react"
import { Button } from "@/components/ui/button"
import { Card } from "@/components/ui/card"
import { cn } from "@/lib/utils"

// Product type definition
type Product = {
  id: number
  name: string
  price: number
  image: string
  quantity: number
}

export default function ShoppingCartComponent() {
  // Initial products in cart
  const [products, setProducts] = useState<Product[]>([
    {
      id: 1,
      name: "Premium Wireless Headphones",
      price: 299,
      image: "/diverse-people-listening-headphones.png",
      quantity: 1,
    },
    {
      id: 2,
      name: "Next-Gen Smartwatch",
      price: 499,
      image: "/modern-smartwatch.png",
      quantity: 1,
    },
    {
      id: 3,
      name: "Portable Bluetooth Speaker",
      price: 199,
      image: "/bluetooth-speaker.png",
      quantity: 2,
    },
  ])

  const [cartOpen, setCartOpen] = useState(true)
  const [checkoutHover, setCheckoutHover] = useState(false)

  // Calculate totals
  const subtotal = products.reduce((sum, product) => sum + product.price * product.quantity, 0)
  const shipping = 25
  const total = subtotal + shipping

  // Update quantity
  const updateQuantity = (id: number, newQuantity: number) => {
    if (newQuantity < 1) return

    setProducts(
      products.map((product) =>
        product.id === id
          ? {
              ...product,
              quantity: newQuantity,
            }
          : product,
      ),
    )
  }

  // Remove product
  const removeProduct = (id: number) => {
    setProducts(products.filter((product) => product.id !== id))
  }

  // Add new product (demo function)
  const addNewProduct = () => {
    const newProduct = {
      id: Date.now(),
      name: "New Product Added",
      price: 149,
      image: "/new-product-launch.png",
      quantity: 1,
    }

    setProducts([...products, newProduct])
  }

  return (
    <div className="w-full max-w-4xl mx-auto p-6 bg-black rounded-xl shadow-lg">
      <div className="flex justify-between items-center mb-6">
        <motion.h2
          className="text-2xl font-bold text-blue-400 flex items-center"
          initial={{ opacity: 0, y: -20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5 }}
        >
          <ShoppingCart className="mr-2" />
          Your Shopping Cart
        </motion.h2>

        <motion.div whileHover={{ scale: 1.05 }} whileTap={{ scale: 0.95 }}>
          <Button
            variant="outline"
            className="border-blue-500 text-blue-500 hover:bg-blue-900 hover:text-blue-100"
            onClick={addNewProduct}
          >
            Add Demo Product
          </Button>
        </motion.div>
      </div>

      <motion.div
        initial={false}
        animate={{ height: cartOpen ? "auto" : 0, opacity: cartOpen ? 1 : 0 }}
        transition={{ duration: 0.3 }}
        className="overflow-hidden"
      >
        <div className="space-y-4 mb-6">
          <AnimatePresence>
            {products.map((product) => (
              <motion.div
                key={product.id}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{
                  opacity: 0,
                  x: -100,
                  transition: { duration: 0.3 },
                }}
                transition={{ duration: 0.3 }}
                layout
                className="relative"
              >
                <Card className="p-4 bg-gray-900 border-gray-800 overflow-hidden">
                  {/* Animated blue accent */}
                  <motion.div
                    className="absolute left-0 top-0 h-full w-1 bg-gradient-to-b from-blue-400 to-blue-600"
                    initial={{ height: 0 }}
                    animate={{ height: "100%" }}
                    transition={{ duration: 0.5, delay: 0.2 }}
                  />

                  <div className="flex items-center">
                    <motion.div
                      className="relative h-20 w-20 rounded-md overflow-hidden bg-gray-800 flex-shrink-0"
                      whileHover={{ scale: 1.05 }}
                    >
                      <img
                        src={product.image || "/placeholder.svg"}
                        alt={product.name}
                        className="h-full w-full object-cover"
                      />
                    </motion.div>

                    <div className="ml-4 flex-grow">
                      <h3 className="font-semibold text-white">{product.name}</h3>
                      <p className="text-blue-400 font-bold mt-1">${product.price.toLocaleString()}</p>
                    </div>

                    <div className="flex flex-col items-end gap-2">
                      <div className="flex items-center bg-gray-800 rounded-md">
                        <motion.button
                          whileHover={{ scale: 1.1 }}
                          whileTap={{ scale: 0.9 }}
                          className="p-1 text-gray-400 hover:text-blue-400"
                          onClick={() => updateQuantity(product.id, product.quantity - 1)}
                        >
                          <Minus size={16} />
                        </motion.button>

                        <motion.span
                          key={product.quantity}
                          initial={{ scale: 1.5, opacity: 0 }}
                          animate={{ scale: 1, opacity: 1 }}
                          className="w-8 text-center font-medium"
                        >
                          {product.quantity}
                        </motion.span>

                        <motion.button
                          whileHover={{ scale: 1.1 }}
                          whileTap={{ scale: 0.9 }}
                          className="p-1 text-gray-400 hover:text-blue-400"
                          onClick={() => updateQuantity(product.id, product.quantity + 1)}
                        >
                          <Plus size={16} />
                        </motion.button>
                      </div>

                      <motion.button
                        whileHover={{ scale: 1.1, color: "#3b82f6" }}
                        whileTap={{ scale: 0.9 }}
                        className="text-gray-400"
                        onClick={() => removeProduct(product.id)}
                      >
                        <Trash2 size={16} />
                      </motion.button>
                    </div>
                  </div>

                  {/* Animated total for this product */}
                  <motion.div
                    key={`${product.id}-${product.quantity}`}
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    className="text-right mt-2 text-sm text-gray-400"
                  >
                    Total:{" "}
                    <span className="text-blue-400 font-semibold">
                      ${(product.price * product.quantity).toLocaleString()}
                    </span>
                  </motion.div>
                </Card>
              </motion.div>
            ))}
          </AnimatePresence>

          {products.length === 0 && (
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={{ duration: 0.5 }}
              className="text-center py-8"
            >
              <div className="flex justify-center mb-4">
                <motion.div
                  animate={{
                    y: [0, -10, 0],
                    rotateZ: [0, -5, 5, 0],
                  }}
                  transition={{
                    duration: 2,
                    repeat: Number.POSITIVE_INFINITY,
                    repeatType: "reverse",
                  }}
                >
                  <ShoppingCart size={48} className="text-gray-700" />
                </motion.div>
              </div>
              <p className="text-gray-500">Your cart is empty</p>
              <motion.button
                whileHover={{ scale: 1.05 }}
                whileTap={{ scale: 0.95 }}
                className="mt-4 text-blue-500 hover:text-blue-400"
                onClick={addNewProduct}
              >
                Add Products
              </motion.button>
            </motion.div>
          )}
        </div>
      </motion.div>

      {products.length > 0 && (
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5, delay: 0.2 }}
        >
          <Card className="p-5 bg-gray-900 border-gray-800">
            <h3 className="text-lg font-semibold text-white mb-4">Order Summary</h3>

            <div className="space-y-2 mb-4">
              <div className="flex justify-between">
                <span className="text-gray-400">Subtotal</span>
                <motion.span
                  key={subtotal}
                  initial={{ opacity: 0, x: -10 }}
                  animate={{ opacity: 1, x: 0 }}
                  className="font-medium"
                >
                  ${subtotal.toLocaleString()}
                </motion.span>
              </div>

              <div className="flex justify-between">
                <span className="text-gray-400">Shipping</span>
                <span className="font-medium">${shipping.toLocaleString()}</span>
              </div>

              <div className="border-t border-gray-800 pt-2 mt-2">
                <div className="flex justify-between">
                  <span className="font-semibold text-white">Total</span>
                  <motion.span
                    key={total}
                    initial={{ scale: 1.2, color: "#3b82f6" }}
                    animate={{ scale: 1, color: "#ffffff" }}
                    transition={{ duration: 0.5 }}
                    className="font-bold text-lg"
                  >
                    ${total.toLocaleString()}
                  </motion.span>
                </div>
              </div>
            </div>

            <motion.div
              whileHover={{ scale: 1.02 }}
              whileTap={{ scale: 0.98 }}
              onHoverStart={() => setCheckoutHover(true)}
              onHoverEnd={() => setCheckoutHover(false)}
            >
              <Button
                className={cn(
                  "w-full transition-all duration-300 relative overflow-hidden",
                  "bg-gradient-to-r from-blue-700 to-blue-600 hover:from-blue-800 hover:to-blue-700 text-white",
                )}
              >
                <motion.div
                  className="absolute inset-0 bg-blue-500"
                  initial={{ x: "-100%" }}
                  animate={{ x: checkoutHover ? "0%" : "-100%" }}
                  transition={{ duration: 0.3 }}
                  style={{ opacity: 0.2 }}
                />

                <motion.div
                  className="flex items-center justify-center relative z-10"
                  animate={{
                    x: checkoutHover ? [5, 0] : 0,
                  }}
                  transition={{ duration: 0.2, repeat: checkoutHover ? 3 : 0, repeatType: "reverse" }}
                >
                  <span>Proceed to Checkout</span>
                  <CreditCard className="ml-2" size={18} />
                </motion.div>
              </Button>
            </motion.div>

            <div className="flex items-center justify-center mt-4 text-xs text-gray-500">
              <Package size={14} className="mr-1" />
              <span>Fast shipping within 3-5 business days</span>
            </div>
          </Card>
        </motion.div>
      )}
    </div>
  )
}
